import { useMemo } from 'react';
import { questions, categories } from '../data/questions';

// 受限分类：仅指定账号可见
const RESTRICTED_CATEGORIES = ['简历针对', '技能考察', '一面追问', '二面深度', '美团项目'];

// 有权限查看受限分类的 GitHub 用户名
const ALLOWED_USERS = ['xiaopeng1112'];

export function useQuestionAccess(login: string | undefined) {
  const hasAccess = !!login && ALLOWED_USERS.includes(login);

  const availableCategories = useMemo(() => {
    if (hasAccess) return categories;
    return categories.filter(c => !RESTRICTED_CATEGORIES.includes(c));
  }, [hasAccess]);

  const availableQuestions = useMemo(() => {
    if (hasAccess) return questions;
    return questions.filter(q => !RESTRICTED_CATEGORIES.includes(q.category));
  }, [hasAccess]);

  return { availableCategories, availableQuestions, hasFullAccess: hasAccess };
}
